## 第三部分：无限重渲染问题的根本原因与解决方案

### 3.1 问题案例分析

#### 案例1：对象依赖导致的无限循环
```javascript
// ❌ 错误示例
function UserComponent({ userId }) {
  const [userData, setUserData] = useState(null);

  const fetchOptions = {
    method: 'GET',
    headers: { 'Content-Type': 'application/json' }
  };

  useEffect(() => {
    fetchUserData(userId, fetchOptions).then(setUserData);
  }, [userId, fetchOptions]); // fetchOptions 每次都是新对象！

  return <div>{userData?.name}</div>;
}
```

**问题分析：**
1. 每次渲染时，`fetchOptions` 都是新创建的对象
2. `Object.is(oldOptions, newOptions)` 始终返回 `false`
3. useEffect 认为依赖发生变化，重新执行
4. 重新执行导致组件重新渲染
5. 进入无限循环

#### 解决方案1：移动对象到 Effect 内部
```javascript
// ✅ 正确示例1
function UserComponent({ userId }) {
  const [userData, setUserData] = useState(null);

  useEffect(() => {
    const fetchOptions = {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' }
    };

    fetchUserData(userId, fetchOptions).then(setUserData);
  }, [userId]); // 只依赖 userId

  return <div>{userData?.name}</div>;
}
```

#### 解决方案2：使用 useMemo 缓存对象
```javascript
// ✅ 正确示例2
function UserComponent({ userId }) {
  const [userData, setUserData] = useState(null);

  const fetchOptions = useMemo(() => ({
    method: 'GET',
    headers: { 'Content-Type': 'application/json' }
  }), []); // 空依赖，对象不会重新创建

  useEffect(() => {
    fetchUserData(userId, fetchOptions).then(setUserData);
  }, [userId, fetchOptions]);

  return <div>{userData?.name}</div>;
}
```

#### 解决方案3：使用 useCallback 缓存函数
```javascript
// ✅ 正确示例3
function UserComponent({ userId }) {
  const [userData, setUserData] = useState(null);

  const fetchUser = useCallback(async () => {
    const options = {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' }
    };
    const data = await fetchUserData(userId, options);
    setUserData(data);
  }, [userId]); // 只有 userId 变化时才重新创建函数

  useEffect(() => {
    fetchUser();
  }, [fetchUser]);

  return <div>{userData?.name}</div>;
}
```

### 3.2 常见陷阱与解决模式

#### 陷阱1：在 Effect 中直接设置状态
```javascript
// ❌ 可能导致无限循环
function SearchComponent() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);

  useEffect(() => {
    if (!query) {
      setResults([]); // 这里可能导致问题
      return;
    }

    searchAPI(query).then(setResults);
  }, [query, results]); // ❌ 依赖了 results
}

// ✅ 正确做法
function SearchComponent() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);

  useEffect(() => {
    if (!query) {
      setResults([]);
      return;
    }

    searchAPI(query).then(setResults);
  }, [query]); // ✅ 只依赖 query
}
```

#### 陷阱2：复杂对象的比较
```javascript
// ❌ 用户信息对象变化导致重新获取
function UserProfile({ user }) {
  const [profileData, setProfileData] = useState(null);

  useEffect(() => {
    fetchProfile(user.id).then(setProfileData);
  }, [user]); // user 对象可能经常变化
}

// ✅ 只依赖真正需要的属性
function UserProfile({ user }) {
  const [profileData, setProfileData] = useState(null);

  useEffect(() => {
    fetchProfile(user.id).then(setProfileData);
  }, [user.id]); // 只依赖 user.id
}
```

