## 第四部分：企业级应用最佳实践

### 4.1 自定义 Hook 封装模式

#### 数据获取 Hook
```javascript
// hooks/useApiData.js
function useApiData(url, dependencies = []) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const controller = useRef(null);

  useEffect(() => {
    // 取消之前的请求
    if (controller.current) {
      controller.current.abort();
    }

    controller.current = new AbortController();

    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);

        const response = await fetch(url, {
          signal: controller.current.signal
        });

        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }

        const result = await response.json();
        setData(result);
      } catch (err) {
        if (err.name !== 'AbortError') {
          setError(err);
        }
      } finally {
        setLoading(false);
      }
    };

    fetchData();

    return () => {
      if (controller.current) {
        controller.current.abort();
      }
    };
  }, dependencies);

  return { data, loading, error };
}

// 使用示例
function UserList() {
  const { data: users, loading, error } = useApiData('/api/users', []);

  if (loading) return <LoadingSpinner />;
  if (error) return <ErrorMessage error={error} />;

  return (
    <ul>
      {users?.map(user => (
        <li key={user.id}>{user.name}</li>
      ))}
    </ul>
  );
}
```

#### 防抖 Hook
```javascript
// hooks/useDebounce.js
function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
}

// 实际应用
function SearchInput() {
  const [query, setQuery] = useState('');
  const debouncedQuery = useDebounce(query, 300);
  const { data: results } = useApiData(
    `/api/search?q=${debouncedQuery}`,
    [debouncedQuery]
  );

  return (
    <div>
      <input
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        placeholder="搜索..."
      />
      <SearchResults results={results} />
    </div>
  );
}
```

### 4.2 性能优化模式

#### 避免不必要的 Effect 执行
```javascript
// ✅ 使用 useMemo 缓存计算结果
function ExpensiveComponent({ items, filter }) {
  const filteredItems = useMemo(() => {
    console.log('执行昂贵的过滤计算');
    return items.filter(item =>
      item.name.toLowerCase().includes(filter.toLowerCase())
    );
  }, [items, filter]);

  // 只在过滤结果变化时执行 Effect
  useEffect(() => {
    console.log(`过滤后有 ${filteredItems.length} 个项目`);
  }, [filteredItems.length]); // 依赖长度而不是整个数组

  return <ItemList items={filteredItems} />;
}
```

#### 批量状态更新
```javascript
// ❌ 多次状态更新可能导致多次渲染
function FormComponent() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');

  const handleSubmit = () => {
    setName('');    // 渲染1
    setEmail('');   // 渲染2
    setPhone('');   // 渲染3
  };
}

// ✅ 使用 useReducer 或状态对象
function FormComponent() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: ''
  });

  const handleSubmit = () => {
    setFormData({
      name: '',
      email: '',
      phone: ''
    }); // 只渲染1次
  };
}
```

### 4.3 错误处理与清理模式

#### 网络请求的正确清理
```javascript
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    const controller = new AbortController();

    const fetchUser = async () => {
      try {
        setLoading(true);

        const response = await fetch(`/api/users/${userId}`, {
          signal: controller.signal
        });

        const userData = await response.json();

        // 检查组件是否已卸载
        if (!cancelled) {
          setUser(userData);
          setLoading(false);
        }
      } catch (error) {
        if (error.name !== 'AbortError' && !cancelled) {
          console.error('获取用户失败:', error);
          setLoading(false);
        }
      }
    };

    fetchUser();

    return () => {
      cancelled = true;
      controller.abort();
    };
  }, [userId]);

  if (loading) return <div>加载中...</div>;
  return <div>{user?.name}</div>;
}
```

#### 事件监听器的清理
```javascript
function WindowSizeTracker() {
  const [windowSize, setWindowSize] = useState({
    width: window.innerWidth,
    height: window.innerHeight
  });

  useEffect(() => {
    const handleResize = () => {
      setWindowSize({
        width: window.innerWidth,
        height: window.innerHeight
      });
    };

    // 添加事件监听器
    window.addEventListener('resize', handleResize);

    // 清理函数：移除事件监听器
    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []); // 空依赖数组，只在挂载/卸载时执行

  return <div>{windowSize.width} x {windowSize.height}</div>;
}
```

