## 第五部分：调试技巧与工具

### 5.1 Effect 执行追踪
```javascript
function useEffectDebugger(effectHook, dependencies, dependencyNames = []) {
  const previousDeps = useRef(dependencies);
  const changedDeps = useRef([]);

  useEffect(() => {
    const changes = [];

    if (previousDeps.current) {
      for (let i = 0; i < dependencies.length; i++) {
        if (!Object.is(dependencies[i], previousDeps.current[i])) {
          changes.push({
            name: dependencyNames[i] || i,
            before: previousDeps.current[i],
            after: dependencies[i]
          });
        }
      }
    }

    if (changes.length > 0) {
      console.log('[Effect Debug] 依赖变化:', changes);
    }

    changedDeps.current = changes;
    previousDeps.current = dependencies;

    return effectHook();
  }, dependencies);
}

// 使用示例
function MyComponent({ userId, settings }) {
  useEffectDebugger(() => {
    fetchUserData(userId, settings);
  }, [userId, settings], ['userId', 'settings']);
}
```

### 5.2 使用 React DevTools
```javascript
// 在组件中添加调试信息
function MyComponent() {
  useDebugValue('组件状态描述');

  const customHook = useCustomHook();
  useDebugValue(customHook, value => `Hook状态: ${JSON.stringify(value)}`);

  return <div>...</div>;
}
```

