## 总结与检查清单

### useEffect 使用检查清单
- [ ] Effect 中的所有变量都在依赖数组中？
- [ ] 依赖数组中的对象/函数是否会频繁重新创建？
- [ ] 是否正确处理了异步操作的清理？
- [ ] 是否有潜在的内存泄漏？
- [ ] Effect 的执行时机是否符合预期？

### 性能优化检查清单
- [ ] 使用 useMemo 缓存昂贵的计算？
- [ ] 使用 useCallback 缓存函数引用？
- [ ] 避免在依赖数组中使用整个对象？
- [ ] 合理使用空依赖数组？
- [ ] 考虑将 Effect 拆分为多个更小的 Effect？

通过掌握这些概念和最佳实践，你将能够在企业级 React 应用中熟练使用 useEffect，避免常见陷阱，并写出高性能、可维护的代码。

记住：理解原理比记住用法更重要！

// 智能搜索组件 - 完整实现示例
import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';

// 自定义防抖 Hook
function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
}

// 搜索历史管理 Hook
function useSearchHistory(maxItems = 10) {
  const [history, setHistory] = useState(() => {
    const saved = localStorage.getItem('searchHistory');
    return saved ? JSON.parse(saved) : [];
  });

  const addToHistory = useCallback((query) => {
    if (!query.trim()) return;

    setHistory(prev => {
      const newHistory = [query, ...prev.filter(item => item !== query)];
      const trimmed = newHistory.slice(0, maxItems);
      localStorage.setItem('searchHistory', JSON.stringify(trimmed));
      return trimmed;
    });
  }, [maxItems]);

  const clearHistory = useCallback(() => {
    setHistory([]);
    localStorage.removeItem('searchHistory');
  }, []);

  return { history, addToHistory, clearHistory };
}

// 主要的智能搜索组件
function SmartSearch() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showHistory, setShowHistory] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);

  const debouncedQuery = useDebounce(query, 300);
  const { history, addToHistory, clearHistory } = useSearchHistory();
  const inputRef = useRef(null);
  const abortControllerRef = useRef(null);

  // 搜索函数
  const performSearch = useCallback(async (searchQuery) => {
    if (!searchQuery.trim()) {
      setResults([]);
      return;
    }

    // 取消之前的请求
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    abortControllerRef.current = new AbortController();

    try {
      setLoading(true);
      setError(null);

      // 模拟 API 调用
      const response = await fetch(`/api/search?q=${encodeURIComponent(searchQuery)}`, {
        signal: abortControllerRef.current.signal
      });

      if (!response.ok) {
        throw new Error(`搜索失败: ${response.status}`);
      }

      const data = await response.json();
      setResults(data.results || []);
    } catch (err) {
      if (err.name !== 'AbortError') {
        setError(err.message);
        setResults([]);
      }
    } finally {
      setLoading(false);
    }
  }, []);

  // 防抖搜索效果
  useEffect(() => {
    performSearch(debouncedQuery);
  }, [debouncedQuery, performSearch]);

  // 键盘事件处理
  const handleKeyDown = useCallback((e) => {
    const itemCount = showHistory ? history.length : results.length;
    const items = showHistory ? history : results;

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setSelectedIndex(prev =>
          prev < itemCount - 1 ? prev + 1 : 0
        );
        break;

      case 'ArrowUp':
        e.preventDefault();
        setSelectedIndex(prev =>
          prev > 0 ? prev - 1 : itemCount - 1
        );
        break;

      case 'Enter':
        e.preventDefault();
        if (selectedIndex >= 0 && selectedIndex < itemCount) {
          const selectedItem = items[selectedIndex];
          const selectedQuery = showHistory ? selectedItem : selectedItem.title;

          setQuery(selectedQuery);
          addToHistory(selectedQuery);
          setShowHistory(false);
          setSelectedIndex(-1);

          if (showHistory) {
            performSearch(selectedQuery);
          }
        } else if (query.trim()) {
          addToHistory(query);
          setShowHistory(false);
        }
        break;

      case 'Escape':
        e.preventDefault();
        setShowHistory(false);
        setSelectedIndex(-1);
        inputRef.current?.blur();
        break;

      default:
        break;
    }
  }, [selectedIndex, showHistory, history, results, query, addToHistory, performSearch]);

  // 输入变化处理
  const handleInputChange = useCallback((e) => {
    const newQuery = e.target.value;
    setQuery(newQuery);
    setSelectedIndex(-1);

    // 如果输入为空，显示搜索历史
    if (!newQuery.trim() && history.length > 0) {
      setShowHistory(true);
    } else {
      setShowHistory(false);
    }
  }, [history.length]);

  // 焦点事件处理
  const handleFocus = useCallback(() => {
    if (!query.trim() && history.length > 0) {
      setShowHistory(true);
    }
  }, [query, history.length]);

  const handleBlur = useCallback(() => {
    // 延迟隐藏，允许点击列表项
    setTimeout(() => {
      setShowHistory(false);
      setSelectedIndex(-1);
    }, 200);
  }, []);

  // 清理函数
  useEffect(() => {
    return () => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, []);

  // 渲染搜索结果或历史
  const renderDropdown = useMemo(() => {
    const items = showHistory ? history : results;
    const isHistoryMode = showHistory;

    if (items.length === 0 && !loading) {
      if (isHistoryMode) {
        return null;
      }
      return query.trim() ? (
        <div className="search-dropdown">
          <div className="search-empty">未找到相关结果</div>
        </div>
      ) : null;
    }

    return (
      <div className="search-dropdown">
        {isHistoryMode && (
          <div className="search-dropdown-header">
            <span>搜索历史</span>
            <button onClick={clearHistory} className="clear-history">
              清空
            </button>
          </div>
        )}

        {items.map((item, index) => {
          const isSelected = index === selectedIndex;
          const displayText = isHistoryMode ? item : item.title;

          return (
            <div
              key={isHistoryMode ? item : item.id}
              className={`search-item ${isSelected ? 'selected' : ''}`}
              onClick={() => {
                setQuery(displayText);
                addToHistory(displayText);
                setShowHistory(false);

                if (isHistoryMode) {
                  performSearch(displayText);
                }
              }}
            >
              {isHistoryMode ? (
