// 在线状态检测 Hook - 完整实现示例
import { useState, useEffect, useCallback, useRef } from 'react';

/**
 * 检测用户在线状态的自定义 Hook
 * 包含网络状态、页面可见性和自动重连机制
 */
function useOnlineStatus() {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isVisible, setIsVisible] = useState(!document.hidden);
  const [lastOnlineTime, setLastOnlineTime] = useState(Date.now());
  const [reconnectAttempts, setReconnectAttempts] = useState(0);

  const heartbeatIntervalRef = useRef(null);
  const reconnectTimeoutRef = useRef(null);

  // 网络状态检测
  useEffect(() => {
    const handleOnline = () => {
      console.log('网络连接已恢复');
      setIsOnline(true);
      setLastOnlineTime(Date.now());
      setReconnectAttempts(0);
    };

    const handleOffline = () => {
      console.log('网络连接已断开');
      setIsOnline(false);
    };

    // 添加网络状态监听器
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // 页面可见性检测
  useEffect(() => {
    const handleVisibilityChange = () => {
      const visible = !document.hidden;
      console.log(`页面${visible ? '可见' : '隐藏'}`);
      setIsVisible(visible);

      if (visible && isOnline) {
        // 页面重新可见时，检查连接状态
        checkConnection();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [isOnline]);

  // 连接检查函数
  const checkConnection = useCallback(async () => {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 5000);

      const response = await fetch('/api/health', {
        method: 'GET',
        signal: controller.signal,
        cache: 'no-cache'
      });

      clearTimeout(timeoutId);

      if (response.ok) {
        setIsOnline(true);
        setLastOnlineTime(Date.now());
        setReconnectAttempts(0);
        return true;
      } else {
        throw new Error(`Health check failed: ${response.status}`);
      }
    } catch (error) {
      console.warn('连接检查失败:', error.message);
      setIsOnline(false);
      return false;
    }
  }, []);

  // 自动重连机制
  const attemptReconnect = useCallback(() => {
    if (reconnectAttempts >= 5) {
      console.log('重连次数已达上限，停止重连');
      return;
    }

    const delay = Math.min(1000 * Math.pow(2, reconnectAttempts), 30000); // 指数退避，最大30秒
    console.log(`第 ${reconnectAttempts + 1} 次重连，${delay}ms 后开始`);

    reconnectTimeoutRef.current = setTimeout(async () => {
      setReconnectAttempts(prev => prev + 1);

      const connected = await checkConnection();
      if (!connected) {
        attemptReconnect();
      }
    }, delay);
  }, [reconnectAttempts, checkConnection]);

  // 心跳检测
  useEffect(() => {
    if (!isOnline || !isVisible) {
      if (heartbeatIntervalRef.current) {
        clearInterval(heartbeatIntervalRef.current);
        heartbeatIntervalRef.current = null;
      }
      return;
    }

    // 只在页面可见且在线时启动心跳
    heartbeatIntervalRef.current = setInterval(async () => {
      const connected = await checkConnection();
      if (!connected) {
        attemptReconnect();
      }
    }, 30000); // 每30秒检查一次

    return () => {
      if (heartbeatIntervalRef.current) {
        clearInterval(heartbeatIntervalRef.current);
      }
    };
  }, [isOnline, isVisible, checkConnection, attemptReconnect]);

  // 手动重连函数
  const manualReconnect = useCallback(async () => {
    console.log('手动重连中...');
    setReconnectAttempts(0);

    // 清除自动重连
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }

    const connected = await checkConnection();
    if (!connected) {
      attemptReconnect();
    }

    return connected;
  }, [checkConnection, attemptReconnect]);

  // 清理函数
  useEffect(() => {
    return () => {
      if (heartbeatIntervalRef.current) {
        clearInterval(heartbeatIntervalRef.current);
      }
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
    };
  }, []);

  // 离线时间计算
  const offlineDuration = isOnline ? 0 : Date.now() - lastOnlineTime;

  return {
    isOnline,
    isVisible,
    lastOnlineTime,
    offlineDuration,
    reconnectAttempts,
    manualReconnect,
    checkConnection
  };
}

/**
 * 在线状态显示组件
 */
function OnlineStatusIndicator() {
  const {
    isOnline,
    isVisible,
    offlineDuration,
    reconnectAttempts,
    manualReconnect
  } = useOnlineStatus();

  const formatDuration = (ms) => {
    const seconds = Math.floor(ms / 1000);
    if (seconds < 60) return `${seconds}秒`;

    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes}分${seconds % 60}秒`;

    const hours = Math.floor(minutes / 60);
    return `${hours}小时${minutes % 60}分`;
  };

  if (isOnline && isVisible) {
    return (
      <div className="status-indicator online">
        <span className="status-dot"></span>
        在线
      </div>
    );
  }

  if (isOnline && !isVisible) {
    return (
      <div className="status-indicator background">
        <span className="status-dot"></span>
        后台运行
      </div>
    );
  }

  return (
    <div className="status-indicator offline">
      <span className="status-dot"></span>
      <div className="offline-info">
        <div>离线 {formatDuration(offlineDuration)}</div>
        {reconnectAttempts > 0 && (
          <div className="reconnect-info">
            重连尝试: {reconnectAttempts}/5
          </div>
        )}
        <button
          onClick={manualReconnect}
          className="reconnect-button"
        >
          手动重连
        </button>
      </div>
    </div>
  );
}

