    const changedDeps = deps.map((dep, index) => {
      const prevDep = prevDeps.current[index];
      const hasChanged = !Object.is(dep, prevDep);

      return {
        name: depNames[index] || `依赖${index}`,
        changed: hasChanged,
        before: prevDep,
        after: dep,
      };
    });

    const changes = changedDeps.filter(dep => dep.changed);

    if (changes.length > 0) {
      console.group('依赖变化检测');
      changes.forEach(change => {
        console.log(`${change.name} 发生变化:`, {
          before: change.before,
          after: change.after,
        });
      });
      console.groupEnd();
    }

    prevDeps.current = deps;
  });
}

