## 问题二：闭包陷阱与解决方案

### 闭包陷阱示例
```javascript
// ❌ 闭包陷阱：定时器中获取到的是过期的状态
function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      // 这里的 count 始终是初始值 0
      console.log('当前计数:', count);
      setCount(count + 1); // 每次都是 0 + 1 = 1
    }, 1000);

    return () => clearInterval(timer);
  }, []); // 空依赖数组导致闭包问题

  return <div>{count}</div>;
}
```

### 解决方案

#### 方案 1：使用函数式更新
```javascript
// ✅ 使用函数式更新获取最新状态
function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setCount(prevCount => {
        console.log('当前计数:', prevCount);
        return prevCount + 1; // 总是基于最新状态
      });
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  return <div>{count}</div>;
}
```

#### 方案 2：使用 useRef 获取最新值
```javascript
// ✅ 使用 ref 保存最新的状态值
function Counter() {
  const [count, setCount] = useState(0);
  const countRef = useRef(count);

  // 保持 ref 与状态同步
  useEffect(() => {
    countRef.current = count;
  }, [count]);

  useEffect(() => {
    const timer = setInterval(() => {
      console.log('当前计数:', countRef.current);
      setCount(countRef.current + 1);
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  return <div>{count}</div>;
}
```

#### 方案 3：添加依赖
```javascript
// ✅ 将状态添加到依赖数组中
function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      console.log('当前计数:', count);
      setCount(count + 1);
    }, 1000);

    return () => clearInterval(timer);
  }, [count]); // 每次 count 变化时重新设置定时器

  return <div>{count}</div>;
}
