## 问题四：性能问题的识别与优化

### 性能监控 Hook
```javascript
function useRenderMonitor(componentName, dependencies = []) {
  const renderCount = useRef(0);
  const lastRenderTime = useRef(Date.now());
  const dependencyHistory = useRef([]);

  renderCount.current += 1;

  useEffect(() => {
    const now = Date.now();
    const timeSinceLastRender = now - lastRenderTime.current;

    console.group(`${componentName} 渲染分析 #${renderCount.current}`);
    console.log(`距离上次渲染: ${timeSinceLastRender}ms`);

    // 分析依赖变化
    const prevDeps = dependencyHistory.current[dependencyHistory.current.length - 1];
    if (prevDeps) {
      const changes = dependencies.map((dep, index) => ({
        index,
        changed: !Object.is(dep, prevDeps[index]),
        from: prevDeps[index],
        to: dep,
      })).filter(change => change.changed);

      if (changes.length > 0) {
        console.log('依赖变化:', changes);
      }
    }

    dependencyHistory.current.push([...dependencies]);
    lastRenderTime.current = now;

    console.groupEnd();
  });

  // 在开发环境中警告过度渲染
  useEffect(() => {
    if (process.env.NODE_ENV === 'development' && renderCount.current > 10) {
      console.warn(`${componentName} 在短时间内渲染了 ${renderCount.current} 次，可能存在性能问题`);
    }
  });
}

